import React, { useState, useEffect } from 'react';
import { Page } from '../types';

interface NavbarProps {
  activePage: Page;
  onNavigate: (page: Page) => void;
}

export const Navbar: React.FC<NavbarProps> = ({ activePage, onNavigate }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNav = (page: Page) => {
    onNavigate(page);
    setIsMobileMenuOpen(false);
  };

  return (
    <nav 
        className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 border-b ${
            scrolled 
            ? 'bg-[#1A1625]/90 backdrop-blur-xl border-white/5 py-2 shadow-2xl' 
            : 'bg-transparent border-transparent py-4'
        }`}
    >
      <div className="container flex items-center justify-between">

        {/* Logo Section */}
        <a 
            href="#" 
            onClick={(e) => { e.preventDefault(); handleNav(Page.HOME); }} 
            className="flex items-center gap-3 group relative z-50"
        >
            <div className="w-10 h-10 bg-gradient-to-br from-brand-primary to-brand-secondary rounded-xl flex items-center justify-center font-black text-white text-xl transform group-hover:rotate-12 transition duration-300 shadow-lg shadow-brand-primary/30">
                P
            </div>
            <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-white leading-none">
                    PATCH<span className="text-brand-primary group-hover:text-brand-accent transition duration-300">HUB</span>
                </span>
                <span className="text-[10px] text-slate-400 tracking-widest uppercase opacity-0 group-hover:opacity-100 transition-opacity duration-300 -mt-1">
                    Game Database
                </span>
            </div>
        </a>

        {/* Desktop Navigation */}
        <div className="hidden md:flex items-center gap-1 bg-black/20 backdrop-blur-sm p-1.5 rounded-full border border-white/5 shadow-inner">
            {[
                { page: Page.HOME, icon: 'fas fa-home', label: '首頁' },
                { page: Page.NEWS, icon: 'far fa-newspaper', label: '情報' },
                { page: Page.PATCHES, icon: 'fas fa-database', label: '資料庫' },
                { page: Page.SUBSCRIBE, icon: 'fas fa-gift', label: '福利', highlight: true }
            ].map((item) => (
                <button 
                    key={item.page}
                    onClick={() => handleNav(item.page)} 
                    className={`
                        relative px-5 py-2 rounded-full text-sm font-bold transition-all duration-300 flex items-center gap-2
                        ${activePage === item.page 
                            ? 'bg-gradient-to-r from-brand-primary to-brand-secondary text-white shadow-lg shadow-brand-primary/30' 
                            : 'text-slate-400 hover:text-white hover:bg-white/10'
                        }
                    `}
                >
                    <i className={`${item.icon} ${item.highlight && activePage !== item.page ? 'text-brand-primary group-hover:animate-bounce' : ''}`}></i> 
                    {item.label}
                </button>
            ))}
        </div>

        {/* Right Action Section */}
        <div className="flex items-center gap-4">
            {/* Search Bar - Desktop */}
            <div className="hidden lg:block relative group">
                <input 
                    type="text" 
                    placeholder="搜尋補丁..." 
                    className="bg-brand-dark/50 border border-white/10 rounded-full py-2 px-4 pl-10 text-sm text-white focus:outline-none focus:border-brand-primary focus:bg-brand-dark focus:ring-1 focus:ring-brand-primary w-40 focus:w-60 transition-all duration-300 placeholder-slate-500" 
                />
                <i className="fas fa-search absolute left-3.5 top-2.5 text-slate-500 group-focus-within:text-brand-primary transition"></i>
            </div>

            <div className="h-6 w-px bg-white/10 hidden md:block"></div>

            {/* Member Actions */}
            <button 
                onClick={() => handleNav(Page.DASHBOARD)} 
                className={`hidden sm:flex w-10 h-10 items-center justify-center rounded-full border border-slate-600 hover:border-brand-primary text-slate-300 hover:text-brand-primary transition bg-brand-surface/50 ${activePage === Page.DASHBOARD ? 'border-brand-primary text-brand-primary shadow-[0_0_10px_rgba(245,49,127,0.3)]' : ''}`}
                title="會員中心"
            >
                <i className="fas fa-user"></i>
            </button>

            {activePage === Page.SIGN_UP ? (
                <button 
                    onClick={() => handleNav(Page.HOME)}
                    className="hidden sm:flex items-center gap-2 border border-brand-primary/50 text-white text-xs font-bold px-5 py-2.5 rounded-full hover:bg-brand-primary/10 transition"
                >
                    <i className="fas fa-sign-in-alt"></i>
                    <span>登入</span>
                </button>
            ) : (
                <button 
                    onClick={() => handleNav(Page.SIGN_UP)} 
                    className="hidden sm:flex items-center gap-2 bg-brand-accent hover:bg-cyan-300 text-brand-darker text-xs font-black px-5 py-2.5 rounded-full shadow-[0_0_15px_rgba(0,240,255,0.4)] hover:shadow-[0_0_20px_rgba(0,240,255,0.6)] transition transform hover:scale-105 active:scale-95"
                >
                    <i className="fas fa-crown"></i>
                    <span>白金會員</span>
                </button>
            )}

            {/* Mobile Menu Toggle */}
            <button 
                className="md:hidden text-white text-xl w-10 h-10 flex items-center justify-center rounded-full bg-white/5 hover:bg-white/10 transition border border-white/5"
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            >
                <i className={`fas ${isMobileMenuOpen ? 'fa-times' : 'fa-bars'}`}></i>
            </button>
        </div>
      </div>

      {/* Mobile Dropdown Menu */}
      {isMobileMenuOpen && (
        <div className="absolute top-full left-0 w-full bg-[#1A1625]/95 backdrop-blur-xl border-b border-white/10 shadow-2xl overflow-hidden animate-fade-in z-40">
             <div className="container py-6 flex flex-col gap-3">
                 {[
                    { page: Page.HOME, icon: 'fas fa-home', label: '首頁' },
                    { page: Page.NEWS, icon: 'far fa-newspaper', label: '新聞情報' },
                    { page: Page.PATCHES, icon: 'fas fa-database', label: '補丁資料庫' },
                    { page: Page.SUBSCRIBE, icon: 'fas fa-gift', label: '會員福利' },
                    { page: Page.DASHBOARD, icon: 'fas fa-user-circle', label: '會員中心' }
                 ].map(item => (
                     <button 
                        key={item.page}
                        onClick={() => handleNav(item.page)} 
                        className="w-full text-left px-4 py-4 rounded-xl text-base font-bold text-slate-300 hover:text-white hover:bg-white/5 transition flex items-center gap-4 border border-transparent hover:border-white/5"
                    >
                        <div className="w-8 h-8 rounded-lg bg-brand-dark flex items-center justify-center text-brand-primary">
                            <i className={`${item.icon}`}></i>
                        </div>
                        {item.label}
                     </button>
                 ))}

                 <div className="h-px bg-white/10 my-2"></div>

                 <button onClick={() => handleNav(Page.SIGN_UP)} className="w-full py-4 rounded-xl bg-gradient-to-r from-brand-primary to-brand-secondary text-white font-bold shadow-lg flex items-center justify-center gap-2">
                    <i className="fas fa-crown"></i> 註冊白金會員
                 </button>
             </div>
        </div>
      )}
    </nav>
  );
};

