export const Hero: React.FC = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isPaused, setIsPaused] = useState(false);

  const nextSlide = useCallback(() => {
    setCurrentSlide((prev) => (prev + 1) % SLIDES.length);
  }, []);

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + SLIDES.length) % SLIDES.length);
  };

  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(nextSlide, 6000); 
    return () => clearInterval(interval);
  }, [nextSlide, isPaused]);

  return (
    <div className="relative w-full h-[500px] lg:h-[600px] overflow-hidden group">
      {/* Background Slides */}
      {SLIDES.map((slide, index) => (
        <div 
            key={slide.id}
            className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
                index === currentSlide ? 'opacity-100 z-10' : 'opacity-0 z-0'
            }`}
        >
            {/* Image with Parallax-like scale effect */}
            <div className={`absolute inset-0 transition-transform duration-[8000ms] ease-linear ${index === currentSlide ? 'scale-110' : 'scale-100'}`}>
                <img 
                    src={slide.image} 
                    alt={slide.title} 
                    className="w-full h-full object-cover"
                />
            </div>

            {/* Gradient Overlays for Readability */}
            <div className="absolute inset-0 bg-gradient-to-t from-[#1A1625] via-[#1A1625]/40 to-transparent"></div>
            <div className="absolute inset-0 bg-gradient-to-r from-[#1A1625]/90 via-transparent to-[#1A1625]/30"></div>
        </div>
      ))}

      {/* Content Layer */}
      <div className="container relative z-20 h-full flex flex-col justify-center">
          <div className="max-w-2xl px-4 lg:px-0 mt-20">
             {SLIDES.map((slide, index) => (
                 <div 
                    key={slide.id} 
                    className={`transition-all duration-700 absolute top-1/2 -translate-y-1/2 ${
                        index === currentSlide ? 'opacity-100 translate-x-0 blur-0' : 'opacity-0 -translate-x-10 blur-sm pointer-events-none'
                    }`}
                >
                    <span className="inline-block py-1 px-3 rounded border border-brand-primary/50 text-brand-primary text-xs font-bold tracking-widest mb-4 bg-brand-primary/10 backdrop-blur-md">
                        {slide.tag}
                    </span>
                    <h1 className="text-4xl md:text-6xl font-black text-white mb-4 leading-tight drop-shadow-2xl">
                        {slide.title}
