          <button 
              onClick={prevSlide}
              onMouseEnter={() => setIsPaused(true)}
              onMouseLeave={() => setIsPaused(false)}
              className="w-12 h-12 rounded-full border border-white/20 bg-black/30 backdrop-blur text-white hover:bg-brand-primary hover:border-brand-primary transition-all flex items-center justify-center"
          >
              <i className="fas fa-chevron-left"></i>
          </button>
          <div className="flex gap-2">
            {SLIDES.map((_, idx) => (
                <div key={idx} className="w-16 h-1 bg-white/20 rounded-full overflow-hidden">
                     <div 
                        className={`h-full bg-brand-primary transition-all duration-300 ${idx === currentSlide ? 'w-full' : 'w-0'}`}
                    ></div>
                </div>
            ))}
          </div>
          <button 
              onClick={nextSlide}
              onMouseEnter={() => setIsPaused(true)}
              onMouseLeave={() => setIsPaused(false)}
              className="w-12 h-12 rounded-full border border-white/20 bg-black/30 backdrop-blur text-white hover:bg-brand-primary hover:border-brand-primary transition-all flex items-center justify-center"
          >
              <i className="fas fa-chevron-right"></i>
          </button>
      </div>
    </div>
  );
};

